.sig-cyberpunk-hero {
  position: relative;
  width: min(100%, 980px);
  min-height: 440px;
  display: grid;
  grid-template-columns: minmax(0, 1.08fr) minmax(260px, 0.82fr);
  gap: 34px;
  align-items: stretch;
  padding: 42px;
  overflow: hidden;
  border: 1px solid rgba(34,211,238,0.34);
  border-radius: 10px;
  background: linear-gradient(145deg, #090b1a, rgba(34,211,238,0.08));
  color: #f8fbff;
  box-shadow: 0 30px 80px rgba(34,211,238,0.12);
  font-family: Inter, ui-sans-serif, system-ui, sans-serif;
}
.sig-cyberpunk-hero::before { content: ""; position: absolute; inset: 0; background: linear-gradient(90deg, rgba(34,211,238,0.10) 1px, transparent 1px), linear-gradient(0deg, rgba(255,43,214,0.07) 1px, transparent 1px); background-size: 42px 42px; opacity: 0.78; pointer-events: none; }
.sig-cyberpunk-hero > * { position: relative; z-index: 1; }
.sig-cyberpunk-hero .copy { display: grid; align-content: center; gap: 18px; }
.sig-cyberpunk-hero .kicker { width: fit-content; border: 1px solid rgba(34,211,238,0.34); border-radius: 999px; padding: 6px 10px; color: #22d3ee; background: rgba(34,211,238,0.08); font-size: 11px; font-weight: 800; text-transform: uppercase; letter-spacing: 0; }
.sig-cyberpunk-hero h1 { margin: 0; max-width: 620px; font-family: Inter, ui-sans-serif, system-ui, sans-serif; font-size: clamp(40px, 6.4vw, 70px); font-weight: 760; line-height: 0.98; letter-spacing: 0; }
.sig-cyberpunk-hero p { margin: 0; max-width: 560px; color: #93a4b8; font-size: 15px; line-height: 1.78; }
.sig-cyberpunk-hero .actions { display: flex; flex-wrap: wrap; gap: 10px; padding-top: 6px; }
.sig-cyberpunk-hero button { height: 40px; padding: 0 16px; border-radius: calc(10px / 2 + 4px); border: 1px solid rgba(34,211,238,0.34); font: inherit; font-size: 13px; font-weight: 700; cursor: pointer; transition: transform 180ms cubic-bezier(0.16, 1, 0.3, 1), border-color 180ms; }
.sig-cyberpunk-hero .primary { background: #22d3ee; color: #060817; border-color: #22d3ee; }
.sig-cyberpunk-hero .secondary { background: transparent; color: #f8fbff; }
.sig-cyberpunk-hero button:hover { transform: translateY(-1px); border-color: #22d3ee; }
.sig-cyberpunk-hero .artifact { display: grid; align-content: space-between; gap: 18px; padding: 22px; border: 1px solid rgba(34,211,238,0.34); border-radius: calc(10px - 2px); background: rgba(34,211,238,0.08); backdrop-filter: blur(18px) saturate(140%); }
.sig-cyberpunk-hero .artifact h2 { margin: 0; font-size: 13px; color: #22d3ee; text-transform: uppercase; letter-spacing: 0; }
.sig-cyberpunk-hero .metric-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; }
.sig-cyberpunk-hero .metric { padding: 14px; border: 1px solid rgba(34,211,238,0.34); border-radius: calc(10px - 4px); background: color-mix(in srgb, #090b1a 76%, transparent); }
.sig-cyberpunk-hero .metric strong { display: block; font-size: 30px; line-height: 1; font-variant-numeric: tabular-nums; }
.sig-cyberpunk-hero .metric span { display: block; margin-top: 6px; color: #93a4b8; font-size: 11px; }
.sig-cyberpunk-hero .rail { height: 9px; border-radius: 999px; background: linear-gradient(90deg, #22d3ee, #ff2bd6); }
@media (max-width: 780px) { .sig-cyberpunk-hero { grid-template-columns: 1fr; padding: 28px; } }

.sig-cyberpunk-card { width: min(100%, 390px); padding: 22px; border: 1px solid rgba(34,211,238,0.34); border-radius: 10px; background: #090b1a; color: #f8fbff; box-shadow: 0 30px 80px rgba(34,211,238,0.12); font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.sig-cyberpunk-card .top { display: flex; align-items: start; justify-content: space-between; gap: 16px; margin-bottom: 24px; }
.sig-cyberpunk-card .label { color: #22d3ee; font-size: 12px; font-weight: 800; text-transform: uppercase; letter-spacing: 0; }
.sig-cyberpunk-card .pill { border: 1px solid rgba(34,211,238,0.34); border-radius: 999px; padding: 5px 9px; color: #93a4b8; background: rgba(34,211,238,0.08); font-size: 11px; }
.sig-cyberpunk-card h3 { margin: 0 0 10px; font-family: Inter, ui-sans-serif, system-ui, sans-serif; font-size: 32px; line-height: 1; letter-spacing: 0; }
.sig-cyberpunk-card p { margin: 0; color: #93a4b8; font-size: 13px; line-height: 1.7; }
.sig-cyberpunk-card .strip { display: grid; grid-template-columns: 1fr auto; gap: 12px; margin-top: 22px; padding-top: 16px; border-top: 1px solid rgba(34,211,238,0.34); }
.sig-cyberpunk-card .strip strong { font-variant-numeric: tabular-nums; color: #f8fbff; }
.sig-cyberpunk-card .signal { width: 38px; height: 38px; display: grid; place-items: center; border-radius: calc(10px - 4px); background: #22d3ee; color: #060817; font-weight: 900; }

.sig-cyberpunk-nav { width: min(100%, 900px); min-height: 74px; display: flex; align-items: center; justify-content: space-between; gap: 24px; padding: 14px 16px; border: 1px solid rgba(34,211,238,0.34); border-radius: 10px; background: #090b1a; color: #f8fbff; box-shadow: 0 30px 80px rgba(34,211,238,0.12); font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.sig-cyberpunk-nav .brand { display: flex; align-items: center; gap: 10px; min-width: max-content; font-family: Inter, ui-sans-serif, system-ui, sans-serif; font-size: 15px; font-weight: 800; letter-spacing: 0; }
.sig-cyberpunk-nav .mark { width: 30px; height: 30px; border-radius: calc(10px - 4px); background: linear-gradient(135deg, #22d3ee, #ff2bd6); box-shadow: inset 0 0 0 1px rgba(34,211,238,0.34); }
.sig-cyberpunk-nav .links { display: flex; align-items: center; gap: 4px; min-width: 0; overflow-x: auto; }
.sig-cyberpunk-nav a { height: 34px; display: inline-flex; align-items: center; padding: 0 12px; border-radius: calc(10px - 6px); color: #93a4b8; text-decoration: none; font-size: 13px; transition: color 160ms, background 160ms; white-space: nowrap; }
.sig-cyberpunk-nav a:hover, .sig-cyberpunk-nav a.active { color: #f8fbff; background: rgba(34,211,238,0.08); }
.sig-cyberpunk-nav button { height: 34px; padding: 0 13px; border-radius: calc(10px - 6px); border: 1px solid #22d3ee; background: #22d3ee; color: #060817; font: inherit; font-size: 13px; font-weight: 700; cursor: pointer; white-space: nowrap; }
@media (max-width: 720px) { .sig-cyberpunk-nav { align-items: stretch; flex-direction: column; } }

.sig-cyberpunk-form { width: min(100%, 440px); display: grid; gap: 15px; padding: 22px; border: 1px solid rgba(34,211,238,0.34); border-radius: 10px; background: #090b1a; color: #f8fbff; box-shadow: 0 30px 80px rgba(34,211,238,0.12); font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.sig-cyberpunk-form label { display: grid; gap: 7px; font-size: 13px; font-weight: 800; color: #f8fbff; }
.sig-cyberpunk-form small { color: #93a4b8; font-size: 12px; line-height: 1.55; font-weight: 400; }
.sig-cyberpunk-form .row { display: flex; gap: 10px; }
.sig-cyberpunk-form input { min-width: 0; flex: 1; height: 42px; border-radius: calc(10px - 6px); border: 1px solid rgba(34,211,238,0.34); background: rgba(34,211,238,0.08); color: #f8fbff; padding: 0 12px; font: inherit; outline: none; transition: border-color 160ms, box-shadow 160ms; }
.sig-cyberpunk-form input:focus { border-color: #22d3ee; box-shadow: 0 0 0 3px color-mix(in srgb, #22d3ee 18%, transparent); }
.sig-cyberpunk-form button { height: 42px; padding: 0 14px; border-radius: calc(10px - 6px); border: 1px solid #22d3ee; background: #22d3ee; color: #060817; font: inherit; font-size: 13px; font-weight: 800; cursor: pointer; }
@media (max-width: 520px) { .sig-cyberpunk-form .row { flex-direction: column; } }

.sig-cyberpunk-table { width: min(100%, 780px); overflow: hidden; border: 1px solid rgba(34,211,238,0.34); border-radius: 10px; background: #090b1a; color: #f8fbff; box-shadow: 0 30px 80px rgba(34,211,238,0.12); font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.sig-cyberpunk-table table { width: 100%; border-collapse: collapse; font-size: 13px; }
.sig-cyberpunk-table th, .sig-cyberpunk-table td { padding: 12px 14px; text-align: left; border-bottom: 1px solid rgba(34,211,238,0.34); }
.sig-cyberpunk-table th { color: #93a4b8; font-size: 11px; font-weight: 900; text-transform: uppercase; letter-spacing: 0; background: rgba(34,211,238,0.08); }
.sig-cyberpunk-table td { color: #f8fbff; }
.sig-cyberpunk-table tr:last-child td { border-bottom: 0; }
.sig-cyberpunk-table tbody tr:hover td { background: rgba(34,211,238,0.08); }
.sig-cyberpunk-table .mono { font-variant-numeric: tabular-nums; }
.sig-cyberpunk-table .status { display: inline-flex; align-items: center; gap: 6px; color: #22d3ee; font-weight: 800; }
.sig-cyberpunk-table .status::before { content: ""; width: 7px; height: 7px; border-radius: 50%; background: #22d3ee; }

.bg-perspective-grid {
  min-height: 100vh;
  background: #030712;
  position: relative;
  overflow: hidden;
}
.bg-perspective-grid::before {
  content: '';
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  height: 55%;
  background:
    linear-gradient(to right, rgba(96,165,250,0.06) 0.5px, transparent 0.5px),
    linear-gradient(to bottom, rgba(96,165,250,0.06) 0.5px, transparent 0.5px);
  background-size: 80px 40px;
  transform: perspective(500px) rotateX(65deg);
  transform-origin: bottom center;
  mask-image: linear-gradient(to top, rgba(0,0,0,0.8) 0%, transparent 90%);
  -webkit-mask-image: linear-gradient(to top, rgba(0,0,0,0.8) 0%, transparent 90%);
}

.btn-void-pulse {
  position: relative;
  padding: 13px 28px;
  background: #000;
  color: #60a5fa;
  font-family: 'Inter', system-ui, sans-serif;
  font-size: 13px;
  font-weight: 600;
  letter-spacing: 0.1em;
  text-transform: lowercase;
  border: 1px solid rgba(96, 165, 250, 0.2);
  border-radius: 8px;
  cursor: pointer;
  transition: all 0.4s cubic-bezier(0.16, 1, 0.3, 1);
  box-shadow: 0 0 0 0 rgba(96, 165, 250, 0), inset 0 0 0 0 rgba(96, 165, 250, 0);
}
.btn-void-pulse:hover {
  border-color: rgba(96, 165, 250, 0.5);
  box-shadow: 0 0 24px -4px rgba(96, 165, 250, 0.3), 0 0 80px -8px rgba(96, 165, 250, 0.1), inset 0 0 12px -4px rgba(96, 165, 250, 0.1);
  color: #93c5fd;
}
.btn-void-pulse:active {
  transform: scale(0.97);
  box-shadow: 0 0 12px -2px rgba(96, 165, 250, 0.4), inset 0 0 20px -4px rgba(96, 165, 250, 0.15);
}

.btn-terminal {
  position: relative;
  padding: 10px 20px;
  background: #000;
  color: #4ade80;
  font-family: 'JetBrains Mono', 'Fira Code', monospace;
  font-size: 13px;
  font-weight: 400;
  border: 1px solid #1a1a1a;
  border-radius: 2px;
  cursor: pointer;
  transition: all 0.15s;
}
.btn-terminal::before {
  content: '';
  display: inline-block;
  width: 0;
  overflow: hidden;
  vertical-align: middle;
  transition: width 0.2s;
}
.btn-terminal:hover::before {
  content: '▊ ';
  width: 1.5em;
  animation: cursor-blink 0.8s step-end infinite;
}
.btn-terminal:hover {
  border-color: #4ade80;
  box-shadow: 0 0 8px rgba(74, 222, 128, 0.15);
}
@keyframes cursor-blink {
  50% { opacity: 0; }
}

.fx-border-beam {
  position: relative;
  padding: 32px;
  border-radius: 16px;
  background: #09090b;
  overflow: hidden;
}
.fx-border-beam::before {
  content: '';
  position: absolute;
  inset: 0;
  border-radius: 16px;
  padding: 1px;
  background: conic-gradient(from var(--beam-angle, 0deg), transparent 0%, transparent 85%, rgba(255,255,255,0.5) 90%, rgba(255,255,255,0.8) 92%, rgba(255,255,255,0.5) 94%, transparent 99%);
  -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
  -webkit-mask-composite: xor;
  mask-composite: exclude;
  animation: beam-spin 4s linear infinite;
}
@keyframes beam-spin {
  to { --beam-angle: 360deg; }
}
@property --beam-angle {
  syntax: '<angle>';
  initial-value: 0deg;
  inherits: false;
}
